const row = $('Get Pending').first().json;
let listings = row.listings;
if (typeof listings === 'string') { try { listings = JSON.parse(listings); } catch (e) { listings = []; } }
if (!Array.isArray(listings)) listings = [];
// Emit one item per listing so the next HTTP node fetches each listing-detail page.
// northstar.weichert.com/{id}/ is server-rendered and returns og:image + <title> in static HTML.
return listings.map((l, i) => ({ json: { idx: i, url: l.url, address: l.address || null } }));

const pending = $('Get Pending').first().json;
const queue_id = pending.id;
const sources = $('Build Fetch Items').all().map(i => i.json);   // [{idx,url,address}] in order
const fetched = $input.all().map(i => i.json);                    // aligned 1:1 by index
const esc = (s) => String(s == null ? '' : s).replace(/</g, '&lt;').replace(/>/g, '&gt;');
const ogImage = (html) => { if (!html) return null; const m = String(html).match(/<meta[^>]+og:image[^>]+content=["']?([^"'>\s]+)/i); return m ? m[1] : null; };
const pageTitle = (html) => { if (!html) return null; const m = String(html).match(/<title[^>]*>([^<]+)<\/title>/i); return m ? m[1].trim() : null; };
const addrFromTitle = (t) => { if (!t) return null; const a = t.split(/\s+for sale/i)[0].split(' | ')[0].trim(); return a || null; };
const cards = sources.map((s, i) => {
  const f = fetched[i] || {};
  const html = (f && (f.data || f.body)) || (typeof f === 'string' ? f : '') || '';
  const photo = ogImage(html);
  const address = s.address || addrFromTitle(pageTitle(html)) || null;
  const url = s.url;
  const photoBlock = photo ? `<tr><td style='padding:0;'><img src='${esc(photo)}' alt='${esc(address || 'Listing')}' width='600' style='display:block;width:100%;max-width:600px;height:auto;'></td></tr>` : '';
  return `<table role='presentation' width='100%' cellpadding='0' cellspacing='0' style='margin:0 0 18px;border:1px solid #e5e4de;border-radius:8px;overflow:hidden;'>${photoBlock}<tr><td style='padding:14px 16px;'><div style='font-size:16px;font-weight:bold;color:#0A0F1A;'>${esc(address || 'New Listing')}</div><div style='margin-top:12px;'><a href='${esc(url)}' style='display:inline-block;background:#0A0F1A;color:#ffffff;text-decoration:none;font-size:14px;font-weight:bold;padding:10px 18px;border-radius:6px;'>View Listing &rarr;</a></div></td></tr></table>`;
}).join('');
return [{ json: { queue_id, cards_html: cards, listing_count: sources.length } }];

const cardsHtml = $('Build Cards').first().json.cards_html || '';
const EVAN = 'ded234e3-1c78-45c3-8924-6036e1fcaf60';
const MICH = '451306d1-6437-42b8-8ffe-c16f28803490';
const agents = {};
agents[EVAN] = { name: 'Evan Knutson', phone: '507-210-9140', email: 'eknutson@teamyellownow.com' };
agents[MICH] = { name: 'Michelle Jasinski', phone: '507-210-7967', email: 'mjasinski@teamyellownow.com' };
const BASE = 'https://norrai.app.n8n.cloud/webhook/marketing-opt-out';
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  if (!j.email) continue;
  const a = agents[j.client_id] || agents[EVAN];
  const firstName = String(j.lead_name || '').trim().split(/\s+/)[0] || 'there';
  const optOut = BASE + '?lead_id=' + encodeURIComponent(j.id) + '&token=' + encodeURIComponent(j.opt_out_token || '');
  const html = `<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'></head><body style='margin:0;padding:0;background:#f4f4f2;font-family:Arial,Helvetica,sans-serif;color:#0A0F1A;'><table role='presentation' width='100%' cellpadding='0' cellspacing='0' style='background:#f4f4f2;padding:24px 0;'><tr><td align='center'><table role='presentation' width='600' cellpadding='0' cellspacing='0' style='max-width:600px;width:100%;background:#ffffff;border-radius:10px;overflow:hidden;'><tr><td style='background:#ffce00;padding:22px 28px;'><div style='font-size:18px;font-weight:bold;color:#0A0F1A;'>Weichert, Realtors&reg; &mdash; Heartland</div><div style='font-size:12px;color:#3A3F48;letter-spacing:.04em;'>FARIBAULT, MINNESOTA</div></td></tr><tr><td style='padding:24px 28px 8px;'><p style='margin:0 0 8px;font-size:16px;'>Hi ${firstName},</p><p style='margin:0;font-size:15px;line-height:1.6;color:#3A3F48;'>Here are this week&rsquo;s featured listings in Faribault.</p></td></tr><tr><td style='padding:8px 28px 0;'>${cardsHtml}</td></tr><tr><td style='padding:0 28px;'><p style='margin:8px 0 0;font-size:15px;line-height:1.6;'>Interested in a showing? Call or text <strong>${a.name}</strong> at <a href='tel:${a.phone}' style='color:#1a73a7;'>${a.phone}</a>.</p></td></tr><tr><td style='padding:18px 28px 20px;'><div style='font-size:14px;font-weight:bold;'>${a.name}</div><div style='font-size:13px;color:#3A3F48;'>Weichert, Realtors&reg; &mdash; Heartland</div><div style='font-size:13px;'><a href='tel:${a.phone}' style='color:#1a73a7;'>${a.phone}</a> &middot; <a href='mailto:${a.email}' style='color:#1a73a7;'>${a.email}</a></div></td></tr><tr><td style='padding:16px 28px 24px;background:#fafaf7;border-top:1px solid #eee;'><p style='margin:0;font-size:11px;color:#9EA3AA;line-height:1.6;'>You are receiving this because you are a contact of ${a.name} at Weichert, Realtors&reg; &mdash; Heartland in Faribault, MN.<br><a href='${optOut}' style='color:#9EA3AA;text-decoration:underline;'>Opt out of future listing emails</a></p></td></tr></table></td></tr></table></body></html>`;
  out.push({ json: { email: j.email, lead_name: j.lead_name || '', subject: 'Featured listings this week — ' + a.name, html, agent_name: a.name, agent_email: a.email, client_id: j.client_id } });
}
return out;
